import React from 'react'

export default function (props) {
  let changeStatus=()=>{
    props.turnOnOrOff(props.name,props.n , props.n)
  }
  let printI=()=>{
    if(props.item.status==true)
    return <img onClick={changeStatus}></img>
    else
    return <img onClick={changeStatus}></img>
  }
  return (
    <div>
      <h2>{props.i.name}</h2>
      {printI()}

      
    </div>
  )
}
